const calcField = (calc, setValueField, valueField) => {
    let setVal = {}
    let i = 0;
    while (i < calc.length) {
        if (parseInt(calc[i][calc[i].length - 3].match(/\d+/)) !== valueField[calc[i][0]]) {
            calc.map((calc) => {
                setVal[calc[0]] = parseInt(calc[calc.length - 3].match(/\d+/));
            })
            setValueField(setVal)
            break;
        }
        i++

    }
}
