import React from 'react';
import { withStyles, makeStyles } from '@material-ui/core/styles';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import Paper from '@material-ui/core/Paper';
import CalcTable from './CalcTable';


const useStyles = makeStyles((theme) => ({
    root: {
        paddingLeft: '1rem',
    },
    textContainer: {
        padding: '1rem',
    },
    listIcon: {
        minWidth: '19px',
    },
    advTitle: {
        color: '#00823c',
        paddingTop: 0,
        paddingBottom: '8px',
    },
    titleBox: {
        width: 'inherit',
        position: 'relative',
    },
    boxPosition: {
        color: '#ffff',
        background: 'rgba(0, 130, 90, 0.7)',
        position: 'absolute',
        bottom: '1rem',
        width: 'inherit',
    },
    wrapTable: {
        marginBottom: '2rem',
    },
}))
const StyledTableCell = withStyles(theme => ({

    head: {
        backgroundColor: '#00823c',
        color: theme.palette.common.white,
        fontWeight: 600,
        width: '1rem',
    },
    body: {
        fontSize: 14,
    },

}))(TableCell);
const StyledTableRow = withStyles(theme => ({
    root: {
        '&:nth-of-type(odd)': {
            backgroundColor: '#f1f5dc',
        },
        '&:nth-of-type(even)': {
            backgroundColor: '#c5dfb8',
        },
    },
}))(TableRow);

const CompositionTable=(props)=>{
    const classes = useStyles();
    const data=props.data;
    const align1 = 'center'
    const align2 = 'center'
    let composition = [[],[],[],[]]
    const length = data.chemicalElem.length/2;
    data.chemicalElem.map((elem, i)=>{
        if (i < length){
            composition[0].push(elem);
            composition[1].push(data.chemicalComposition[i]);
        } else {
            composition[2].push(elem);
            composition[3].push(data.chemicalComposition[i]);
        };
    });
    return(
        <TableContainer component={Paper} className={classes.wrapTable}>
            <Table className={classes.table} aria-label="customized table">
                <TableHead>
                    <TableRow>
                        <StyledTableCell align="center" colSpan={length} className={classes.align} >Хімічний склад, г/л.</StyledTableCell>    
                    </TableRow>
                </TableHead>
                <TableBody> 
                    <CalcTable calc={composition}
                                align1={align1}
                                align2={align2} />
                </TableBody>
                <TableHead>
                    <TableRow>
                        <StyledTableCell align="center" colSpan={length} className={classes.align} >Amino + - амінокислоти та гетероциклічні з'єднання з високою біологічною активністю.</StyledTableCell>
                    </TableRow>
                </TableHead>
            </Table>
        </TableContainer>
    )
}
export default CompositionTable;