import React from 'react';
import { Switch, Route } from 'react-router-dom';
import Container from '@material-ui/core/Container';
import Paper from '@material-ui/core/Paper';
import Grid from '@material-ui/core/Grid';
import { makeStyles } from '@material-ui/core/styles';

import ComplexCard from './ComplexCard';
import ComplexPage from './ComplexPage';
import MenuComplex from './MenuComplex';
import Data from '../data/data.json';

const useStyles = makeStyles((theme) => ({


    wrap: {
        fontColor: '02833e',
        [theme.breakpoints.down("sm")]: {
            width: 525,
            fontSize: '2rem',
        },
        paddingBottom: '2rem',
        width: 'inherit',
        paddingTop: '7.9rem',
    },

}))

export default function ComplexAll() {
    const classes = useStyles();
    let title = [];
    let i = 0
    for (let prop in Data[1].drug) {
        title.push([prop]);
        //console.log(Data[1].drug[prop].link)
        title[i].push(Data[1].drug[prop].link)
        i++
    }
    

return(
    <>
    <Container className={classes.wrap}>
        <Paper elevation={3} style={{ background: 'f5f5f5' }}>
            <Grid container spacing={3} justify="center" style={{ paddingTop: '1rem' }}>
                {title.map((title) => (
                    <Grid item xl={4}>
                        <ComplexCard title={title} />
                    </Grid>
                ))}
            </Grid>
        </Paper>
    </Container>
    </>
)
}