import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Card from '@material-ui/core/Card';
import CardActionArea from '@material-ui/core/CardActionArea';
import CardActions from '@material-ui/core/CardActions';
import CardContent from '@material-ui/core/CardContent';
import CardMedia from '@material-ui/core/CardMedia';
import Button from '@material-ui/core/Button';
import Typography from '@material-ui/core/Typography';
import { Link } from 'react-router-dom';
import Grid from '@material-ui/core/Grid';
import ComplexModalOrder from './ComplexModalOrder'

const useStyles = makeStyles({
    root: {
        maxWidth: 345,
    },
    media: {
        height: 140,
    },
    order: {
        backgroundColor: '#ffa000',
        color: '#ffffff',
        margin: '0.4rem',
    },
});

export default function ComplexCard(props) {
    const classes = useStyles();
    const id=props.id;
    const title=props.title;
    const [open, setOpen] = React.useState(false);
    const [modal, setModal] = React.useState(0);
    const handleClickOpen = (e) => {
    const idx = parseInt(e.currentTarget.id.match(/(\d+\.\d+)|(\d+)/g));
        setOpen(true);
        setModal(idx);
        

    };
    const handleClose = () => {
        setOpen(false);
    };
    
    return (
        <Card className={classes.root} id={`complexCard${id}`}>
            <CardActionArea component={Link} to={title[1]}>
                <img src={`/static/img/${title[0].split(' ')[1]}.png`} style={{ width: 'inherit', marginLeft: '1rem',}}/>
                <CardContent>
                    <Typography gutterBottom variant="h5" component="h2">
                        {title[0]}
                    </Typography>
                    <Typography variant="body2" color="textSecondary" component="p">
                        <Button size="small" color="primary" component={Link} to={title[1]}>
                            Дізнатись більше
                        </Button>
          </Typography>
                </CardContent>
            </CardActionArea>
            <CardActions>
                <Grid item xs={12} style={{ textAlign: 'center' }}>
                    <Button size="large" className={classes.order} onClick={handleClickOpen}>
                        Замовити
            </Button>
                </Grid>
            </CardActions>
            <ComplexModalOrder open={open}
                id={modal}
                onClose={handleClose}
                title={title[0]}
                
            />
        </Card>
    );
}