import React, { useState } from 'react';
import Container from '@material-ui/core/Container';
import { makeStyles } from '@material-ui/core/styles';

import { InView } from 'react-intersection-observer';
import Data from '../data/data.json';
import ContentSection from './ContentSection';
import './topmenu.css';
import MenuCrop from './MenuCrop';

const useStyles = makeStyles((theme) => ({
    root:{
        paddingLeft: '1rem',
        marginTop: '8rem',
    },
    textContainer:{
        padding:'1rem',
    },
    listIcon:{
        minWidth: '19px',
    },
    advTitle:{
        color:'#00823c',
        paddingTop:0,
        paddingBottom:'8px',
    },
    titleBox:{
        width: 'inherit',
        position: 'relative',
    },
    boxPosition:{
        color: '#ffff',
        background: 'rgba(0, 130, 90, 0.7)',
        position: 'absolute',
        bottom: '1rem',
        width: 'inherit',
    },
    wrapTable: {
        marginBottom: '2rem',
    },
    wrap: {
        paddingTop: '7.9rem',
    },
}));


const LandingCard =(props)=>{
    const classes = useStyles();
    const data=Data[0].crop;
    const [valueMenu, setValueMenu]=useState(0)
    //console.log('valueMenu', valueMenu);
    const handleSectionActive = (inView, entry) => {
        //console.log('Inview:', inView, 'entry:', entry.target.childNodes[0].id);
        if (inView) {
            setValueMenu((parseInt(entry.target.childNodes[0].id.match(/\d+/))) - 1);
           // console.log('Go to:', entry.target.childNodes[0].id);
        };   
    };
    //console.log('valueMenu',valueMenu);
    return(
        <>
            <MenuCrop valueMenu={valueMenu}
                    setValueMenu={setValueMenu}/>
            <Container  className={classes.wrap}>
                {data.map((data)=>( 
                    <InView as="section" onChange={handleSectionActive}>
                        <ContentSection  
                            data={data}
                            /> 
                    </InView> 
                ))}

            </Container>
        </>
    );

}
export default LandingCard;