import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Toolbar from '@material-ui/core/Toolbar';
import Typography from '@material-ui/core/Typography';
import Button from '@material-ui/core/Button';
import { Link } from 'react-router-dom';

import TopMenu from '../components/TopMenu';
import MobileMenu from '../components/MobileMenu';
import { ReactComponent as Logo } from '../img/logo.svg'

const useStyles = makeStyles((theme) => ({
    root: {
        flexGrow: 1, 
    },
    colorPrimary: {
        backgroundColor: '#F9F9F9',
        position: 'fixed',
        top:0,
        paddingTop:'0.5rem'
    },
    title: {
        flexGrow: 1,
    },
    callTo: {
        color: '#262626',
        textDecoration: 'none',
        [theme.breakpoints.down('xs')]: {
            fontSize: '1rem',
        },
        
    },
    text: {
        marginLeft: 'auto',
    },
    titleText:{
        display:'block',
        [theme.breakpoints.down('xs')]: {
            display:'none',
        },
    },
    logoSize: {
        width: '245px',
        [theme.breakpoints.down('xs')]: {
            width: '150px',
        },
    },
}));

const TopBar = (props)=>{
    const classes = useStyles();
    const valueMenu = props.valueMenu;
    const setValueMenu = props.setValueMenu;
    return (
        <>
            <AppBar position="static" className={classes.colorPrimary}>
                <Toolbar>
                        <Logo className={classes.logoSize} />
                    <div className={classes.titleText}>
                    <Typography variant="h6" className={classes.title} style={{ padding:'0rem 1rem 0rem 1rem', fontSize: '1.5rem', color: '#00823c', fontWeight: '600', fontStyle:'italic'}}>
                        Нова культура землеробства
                     </Typography>
                    </div>
                    <nav>
                        <TopMenu />
                    </nav>
                    <Button className={classes.text}>
                        <Typography variant="h6" className={classes.title}>
                            <a href="tel:+380674070357" className={classes.callTo}>+380 67 407 0357</a>
                        </Typography>
                    </Button>
                    <nav>
                        <MobileMenu />
                    </nav>
                </Toolbar>
            </AppBar>
       </>
    )
}
export default TopBar;