import React from 'react';
import { Switch, Route } from 'react-router-dom';
import { makeStyles } from '@material-ui/core/styles';

import ComplexCard from './ComplexCard';
import ComplexPage from './ComplexPage';
import MenuComplex from './MenuComplex';
import Data from '../data/data.json';
import ComplexAll from './ComplexAll';

const useStyles = makeStyles((theme) => ({

    
    wrap: {
        fontColor: '02833e',
        [theme.breakpoints.down("sm")]: {
            width: 525,
            fontSize: '2rem',
        },
        paddingBottom: '2rem',
        width: 'inherit',
        paddingTop: '7.9rem',
    },
    
}))

const Complex = () => {
  
    return (
        <div>
        <MenuComplex/>
        <Switch>
            <Route exact path='/complex' component={ComplexAll} />
            <Route path='/complex/complex-femoco' render={(props) => (
                <ComplexPage data={Data[1].drug} complex='Multicomplex Mo-Fe-Co'/>)}/>
            <Route path='/complex/complex-mnzn' render={(props) => (
                <ComplexPage data={Data[1].drug} complex='Multicomplex Мn-Zn' />)} />
            <Route path='/complex/complex-mocofemn' render={(props) => (
                <ComplexPage data={Data[1].drug} complex='Multicomplex Mo-Co-Fe-Mn' />)} />
            <Route path='/complex/complex-bcu' render={(props) => (
                <ComplexPage data={Data[1].drug} complex='Multicomplex B-Сu' />)} />
            <Route path='/complex/complex-mg' render={(props) => (
                <ComplexPage data={Data[1].drug} complex='Multicomplex Mg' />)} />
            <Route path='/complex/complex-b' render={(props) => (
                <ComplexPage data={Data[1].drug} complex='Multicomplex B' />)} />
            <Route path='/complex/complex-zn' render={(props) => (
                    <ComplexPage data={Data[1].drug} complex='Multicomplex Zn' />)} />
            <Route path='/complex/complex-bmo' render={(props) => (
                    <ComplexPage data={Data[1].drug} complex='Multicomplex B-Mo' />)} />
            <Route path='/complex/complex-mn' render={(props) => (
                    <ComplexPage data={Data[1].drug} complex='Multicomplex Mn' />)} />
        </Switch>
        </div>
    )
}
export default Complex;
